CREATE SCHEMA IF NOT EXISTS purchase;

CREATE OR REPLACE FUNCTION purchase._article_options()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text := '<option value="">— aucun —</option>';
  v_opts text;
  v_sql text;
  r record;
BEGIN
  -- Priority: catalog > stock > empty
  SELECT 'SELECT ' || n.nspname || '.article_options()'
    INTO v_sql
    FROM pg_namespace n
    JOIN pg_proc p ON p.pronamespace = n.oid AND p.proname = 'article_options'
   WHERE n.nspname = 'catalog';
  IF v_sql IS NOT NULL THEN
    EXECUTE v_sql INTO v_opts;
    RETURN v_html || coalesce(v_opts, '');
  END IF;

  IF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'stock') THEN
    FOR r IN EXECUTE 'SELECT id, reference, designation FROM stock.article WHERE active = true ORDER BY reference'
    LOOP
      v_html := v_html || format('<option value="%s">%s — %s</option>', r.id, pgv.esc(r.reference), pgv.esc(r.designation));
    END LOOP;
  END IF;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION purchase._article_options() IS 'Generate HTML option list from stock.article (dynamic, no hard dep on stock schema)';

CREATE OR REPLACE FUNCTION purchase._commande_form_body(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_fournisseur_name text;
  v_body text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
    SELECT name INTO v_fournisseur_name FROM crm.client WHERE id = v_cmd.fournisseur_id;
  END IF;

  v_body := '';
  IF p_id IS NOT NULL THEN
    v_body := format('<input type="hidden" name="p_id" value="%s">', p_id);
  END IF;

  v_body := v_body
    || pgv.select_search('p_fournisseur_id', pgv.t('purchase.field_fournisseur'),
         'fournisseur_options', pgv.t('purchase.field_search_fournisseur'),
         CASE WHEN p_id IS NOT NULL THEN v_cmd.fournisseur_id::text END,
         v_fournisseur_name)
    || pgv.input('p_objet', 'text', pgv.t('purchase.field_objet'), v_cmd.objet, true)
    || pgv.input('p_date_livraison', 'date', pgv.t('purchase.field_date_livraison'), v_cmd.date_livraison::text)
    || pgv.input('p_conditions_paiement', 'text', pgv.t('purchase.field_conditions'), v_cmd.conditions_paiement)
    || pgv.textarea('p_notes', pgv.t('purchase.field_notes'), v_cmd.notes);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase._commande_form_body(integer) IS 'Helper: returns HTML form fields for commande creation/edition (no form wrapper)';

CREATE OR REPLACE FUNCTION purchase._fournisseur_options()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text := '<option value="">-- Choisir un fournisseur --</option>';
  r record;
BEGIN
  FOR r IN SELECT id, name FROM crm.client WHERE active ORDER BY name LOOP
    v_html := v_html || format('<option value="%s">%s</option>', r.id, pgv.esc(r.name));
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION purchase._fournisseur_options() IS 'HTML select options for CRM clients as suppliers';

CREATE OR REPLACE FUNCTION purchase._next_number(p_prefix text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year text := to_char(now(), 'YYYY');
  v_seq int;
BEGIN
  SELECT coalesce(max(
    regexp_replace(number, '^.*-(\d+)$', '\1')::int
  ), 0) + 1
  INTO v_seq
  FROM purchase.purchase_order
  WHERE number LIKE p_prefix || '-' || v_year || '-%'
  UNION ALL
  SELECT coalesce(max(
    regexp_replace(number, '^.*-(\d+)$', '\1')::int
  ), 0) + 1
  FROM purchase.receipt
  WHERE number LIKE p_prefix || '-' || v_year || '-%'
  ORDER BY 1 DESC LIMIT 1;

  RETURN p_prefix || '-' || v_year || '-' || lpad(v_seq::text, 3, '0');
END;
$function$;
COMMENT ON FUNCTION purchase._next_number(text) IS 'Generate next sequential number (PO-2026-001, REC-2026-001)';

CREATE OR REPLACE FUNCTION purchase._remaining_quantity(p_line_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN (
    SELECT l.quantity - coalesce(sum(rl.quantity_received), 0)
    FROM purchase.order_line l
    LEFT JOIN purchase.receipt_line rl ON rl.line_id = l.id
    WHERE l.id = p_line_id
    GROUP BY l.quantity
  );
END;
$function$;
COMMENT ON FUNCTION purchase._remaining_quantity(integer) IS 'Calculate remaining quantity to receive for an order line';

CREATE OR REPLACE FUNCTION purchase._set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$function$;
COMMENT ON FUNCTION purchase._set_updated_at() IS 'Trigger function to auto-update updated_at timestamp';
DROP TRIGGER IF EXISTS trg_commande_updated_at ON purchase.purchase_order;
CREATE TRIGGER trg_commande_updated_at BEFORE UPDATE ON purchase.purchase_order FOR EACH ROW EXECUTE FUNCTION purchase._set_updated_at();
DROP TRIGGER IF EXISTS trg_facture_fournisseur_updated_at ON purchase.supplier_invoice;
CREATE TRIGGER trg_facture_fournisseur_updated_at BEFORE UPDATE ON purchase.supplier_invoice FOR EACH ROW EXECUTE FUNCTION purchase._set_updated_at();

CREATE OR REPLACE FUNCTION purchase._status_badge(p_status text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN CASE p_status
    WHEN 'draft' THEN pgv.badge(pgv.t('purchase.status_draft'), 'default')
    WHEN 'sent' THEN pgv.badge(pgv.t('purchase.status_sent'), 'primary')
    WHEN 'partially_received' THEN pgv.badge(pgv.t('purchase.status_partially_received'), 'warning')
    WHEN 'received' THEN pgv.badge(pgv.t('purchase.status_received'), 'success')
    WHEN 'cancelled' THEN pgv.badge(pgv.t('purchase.status_cancelled'), 'danger')
    WHEN 'validated' THEN pgv.badge(pgv.t('purchase.status_validated'), 'primary')
    WHEN 'paid' THEN pgv.badge(pgv.t('purchase.status_paid'), 'success')
    ELSE pgv.badge(p_status, 'default')
  END;
END;
$function$;
COMMENT ON FUNCTION purchase._status_badge(text) IS 'Return HTML badge for a purchase status value';

CREATE OR REPLACE FUNCTION purchase._total_ht(p_order_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN coalesce((
    SELECT sum(quantity * unit_price)
    FROM purchase.order_line
    WHERE order_id = p_order_id
  ), 0);
END;
$function$;
COMMENT ON FUNCTION purchase._total_ht(integer) IS 'Total HT for a purchase order';

CREATE OR REPLACE FUNCTION purchase._total_tva(p_order_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN coalesce((
    SELECT sum(quantity * unit_price * tva_rate / 100)
    FROM purchase.order_line
    WHERE order_id = p_order_id
  ), 0);
END;
$function$;
COMMENT ON FUNCTION purchase._total_tva(integer) IS 'Total TVA for a purchase order';

CREATE OR REPLACE FUNCTION purchase._total_ttc(p_order_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN purchase._total_ht(p_order_id) + purchase._total_tva(p_order_id);
END;
$function$;
COMMENT ON FUNCTION purchase._total_ttc(integer) IS 'Total TTC for a purchase order';

CREATE OR REPLACE FUNCTION purchase.article_options(p_search text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_result jsonb := '[]'::jsonb;
BEGIN
  -- Priority: catalog > stock
  IF EXISTS (SELECT 1 FROM pg_namespace n
             JOIN pg_proc p ON p.pronamespace = n.oid AND p.proname = 'article_options'
             WHERE n.nspname = 'catalog'
             AND pg_get_function_arguments(p.oid) LIKE '%p_search text%') THEN
    EXECUTE format('SELECT catalog.article_options(%L)', p_search) INTO v_result;
    RETURN coalesce(v_result, '[]'::jsonb);
  END IF;

  IF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'stock') THEN
    EXECUTE format(
      'SELECT coalesce(jsonb_agg(jsonb_build_object(
         ''value'', id::text,
         ''label'', reference || '' — '' || designation,
         ''detail'', coalesce(unite, ''u'')
       )), ''[]''::jsonb)
       FROM stock.article
       WHERE active = true
         AND (%L = '''' OR reference ILIKE ''%%'' || %L || ''%%'' OR designation ILIKE ''%%'' || %L || ''%%'')
       ORDER BY reference
       LIMIT 30',
      p_search, p_search, p_search
    ) INTO v_result;
  END IF;

  RETURN coalesce(v_result, '[]'::jsonb);
END;
$function$;
COMMENT ON FUNCTION purchase.article_options(text) IS 'Search-select RPC: returns jsonb array of stock articles matching search term';

CREATE OR REPLACE FUNCTION purchase.brand()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN pgv.t('purchase.brand');
END;
$function$;
COMMENT ON FUNCTION purchase.brand() IS 'Brand name for purchase module';

CREATE OR REPLACE FUNCTION purchase.fournisseur_options(p_search text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  SELECT coalesce(jsonb_agg(row_j ORDER BY row_j->>'label'), '[]'::jsonb)
  INTO v_result
  FROM (
    SELECT jsonb_build_object(
      'value', id::text,
      'label', name,
      'detail', coalesce(email, phone, '')
    ) AS row_j
    FROM crm.client
    WHERE active
      AND (p_search = '' OR name ILIKE '%' || p_search || '%' OR email ILIKE '%' || p_search || '%')
    LIMIT 30
  ) sub;

  RETURN coalesce(v_result, '[]'::jsonb);
END;
$function$;
COMMENT ON FUNCTION purchase.fournisseur_options(text) IS 'Search-select RPC: returns jsonb array of CRM clients matching search term';

